module top_module (
    input clk,
    input reset,
    input j,
    input k,
    output q );reg obf_q_reg;

    always @(posedge clk) begin
        if (reset)
            obf_q_reg <= 1'b0;
        else if (j && ~k)
            obf_q_reg <= 1'b1;
        else if (~j && k)
            obf_q_reg <= 1'b0;
        else if (j && k)
            obf_q_reg <= ~obf_q_reg;
    end

    assign q = obf_q_reg;

endmodule
